     1→//! High-level statistical modeling API for Rust
     2→//!
     3→//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
     4→//! and `Glm` (Generalized Linear Models), integrating lower-level crates
     5→//! to provide a complete modeling workflow.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use faer::{Mat, prelude::*};
    11→
    12→/// Statistical modeling errors
    13→#[derive(thiserror::Error, Debug)]
    14→pub enum ModelError {
    15→    /// Linear algebra computation error
    16→    #[error("Linear algebra error: {0}")]
    17→    LinearAlgebra(String),
    18→    /// Invalid model specification
    19→    #[error("Invalid model: {0}")]
    20→    InvalidModel(String),
    21→}
    22→
    23→/// Common trait for all fitted models
    24→pub trait Fit {
    25→    /// Get model coefficients
    26→    fn coefficients(&self) -> &[f64];
    27→
    28→    /// Get fitted values
    29→    fn fitted(&self) -> &[f64];
    30→
    31→    /// Get residuals
    32→    fn residuals(&self) -> &[f64];
    33→
    34→    /// Get model summary
    35→    fn summary(&self) -> ModelSummary;
    36→}
    37→
    38→/// Model summary information
    39→#[derive(Debug)]
    40→pub struct ModelSummary {
    41→    /// Coefficient table
    42→    pub coefficients: Vec<CoefficientRow>,
    43→}
    44→
    45→/// A row in the coefficient table
    46→#[derive(Debug)]
    47→pub struct CoefficientRow {
    48→    /// Variable name
    49→    pub name: String,
    50→    /// Estimated coefficient
    51→    pub estimate: f64,
    52→    /// Standard error
    53→    pub std_error: f64,
    54→    /// t-statistic
    55→    pub t_value: f64,
    56→    /// p-value
    57→    pub p_value: f64,
    58→}
    59→
    60→/// Linear model fitting
    61→pub struct Lm;
    62→
    63→/// Fitted linear model results
    64→#[derive(Debug)]
    65→pub struct LmFit {
    66→    coefficients: Vec<f64>,
    67→    fitted_values: Vec<f64>,
    68→    residuals: Vec<f64>,
    69→    /// Number of observations
    70→    n_obs: usize,
    71→    /// Matrix rank (for rank-deficient matrices)
    72→    rank: usize,
    73→}
    74→
    75→impl Lm {
    76→    /// Fit a linear model using QR decomposition with column pivoting
    77→    /// 
    78→    /// This implementation uses faer's column-pivoted QR decomposition to handle
    79→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    80→    pub fn fit(x_data: &[f64], y_data: &[f64], n_rows: usize, n_cols: usize) -> Result<LmFit, ModelError> {
    81→        if x_data.len() != n_rows * n_cols {
    82→            return Err(ModelError::InvalidModel(
    83→                "Design matrix dimensions don't match data".to_string()
    84→            ));
    85→        }
    86→        
    87→        if y_data.len() != n_rows {
    88→            return Err(ModelError::InvalidModel(
    89→                "Response vector length doesn't match number of observations".to_string()
    90→            ));
    91→        }
    92→
    93→        // Create faer matrices from input data
    94→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
    95→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);
    96→
    97→        // Use column-pivoted QR for numerical stability with rank-deficient matrices
    98→        let qr = x_mat.col_piv_qr();
    99→        
   100→        // Solve the least squares problem: β = R^(-1) * Q^T * y
   101→        let coefficients_mat = qr.solve_lstsq(&y_mat);
   102→        
   103→        // Calculate fitted values: ŷ = X * β
   104→        let fitted_mat = &x_mat * &coefficients_mat;
   105→        
   106→        // Calculate residuals: e = y - ŷ
   107→        let residuals_mat = &y_mat - &fitted_mat;
   108→        
   109→        // Extract results to plain Vec<f64> for API
