     1→//! Exponential family distributions for generalized linear models
     2→//!
     3→//! This crate provides family structs that specify variance functions and
     4→//! default link functions for GLM fitting.
     5→
     6→#![forbid(unsafe_code)]
     7→#![warn(missing_docs)]
     8→
     9→use link::{Identity, LinkFn, Log, Logit};
    10→
    11→/// Trait for exponential family distributions
    12→pub trait Family {
    13→    /// Associated link function type
    14→    type Link: LinkFn;
    15→
    16→    /// Variance function V(μ)
    17→    fn variance(&self, mu: f64) -> f64;
    18→
    19→    /// Default link function
    20→    fn link(&self) -> Self::Link;
    21→
    22→    /// Deviance residual
    23→    fn dev_resid(&self, y: f64, mu: f64) -> f64;
    24→}
    25→
    26→/// Gaussian (normal) family
    27→#[derive(Debug, Default)]
    28→pub struct Gaussian;
    29→
    30→impl Family for Gaussian {
    31→    type Link = Identity;
    32→
    33→    fn variance(&self, _mu: f64) -> f64 {
    34→        1.0
    35→    }
    36→
    37→    fn link(&self) -> Self::Link {
    38→        Identity
    39→    }
    40→
    41→    fn dev_resid(&self, y: f64, mu: f64) -> f64 {
    42→        (y - mu).powi(2)
    43→    }
    44→}
    45→
    46→/// Poisson family
    47→#[derive(Debug, Default)]
    48→pub struct Poisson;
    49→
    50→impl Family for Poisson {
    51→    type Link = Log;
    52→
    53→    fn variance(&self, mu: f64) -> f64 {
    54→        mu
    55→    }
    56→
    57→    fn link(&self) -> Self::Link {
    58→        Log
    59→    }
    60→
    61→    fn dev_resid(&self, y: f64, mu: f64) -> f64 {
    62→        if y == 0.0 {
    63→            2.0 * mu
    64→        } else {
    65→            2.0 * (y * (y / mu).ln() - (y - mu))
    66→        }
    67→    }
    68→}
    69→
