//! Categorical data types with contrast coding for statistical modeling
//!
//! This crate provides first-class types for categorical data, featuring
//! pluggable contrast coding (dummy, sum-to-zero, Helmert, etc.) and
//! support for ordered factors.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use std::sync::Arc;

/// A categorical factor with shared level storage
#[derive(Debug, Clone)]
pub struct Factor<T> {
    /// Level indices for each observation
    indices: Vec<u32>,
    /// Shared level labels
    levels: Arc<Vec<T>>,
}

/// An ordered categorical factor  
#[derive(Debug, Clone)]
pub struct OrderedFactor<T>(#[allow(dead_code)] Factor<T>);

/// Trait for contrast coding schemes
pub trait Contrast {
    /// Generate contrast matrix for the given number of levels
    fn matrix(&self, n_levels: usize) -> Vec<Vec<f64>>;

    /// Number of columns produced by this contrast
    fn n_cols(&self, n_levels: usize) -> usize;
}

/// Treatment (dummy) coding - first level is reference
#[derive(Debug, Default)]
pub struct Dummy;

impl Contrast for Dummy {
    fn matrix(&self, n_levels: usize) -> Vec<Vec<f64>> {
        let mut matrix = Vec::new();
        for i in 1..n_levels {
            let mut row = vec![0.0; n_levels - 1];
            row[i - 1] = 1.0;
            matrix.push(row);
        }
        matrix
    }

    fn n_cols(&self, n_levels: usize) -> usize {
        if n_levels <= 1 {
            0
        } else {
            n_levels - 1
        }
    }
}

/// Sum-to-zero coding
#[derive(Debug, Default)]
pub struct Sum;

impl Contrast for Sum {
    fn matrix(&self, n_levels: usize) -> Vec<Vec<f64>> {
        let mut matrix = Vec::new();
        for i in 0..(n_levels - 1) {
            let mut row = vec![-1.0; n_levels - 1];
            if i < n_levels - 1 {
                row[i] = 1.0;
            }
            matrix.push(row);
        }
        matrix
    }

    fn n_cols(&self, n_levels: usize) -> usize {
        if n_levels <= 1 {
            0
        } else {
            n_levels - 1
        }
    }
}

impl<T> Factor<T>
where
    T: Clone + PartialEq,
{
    /// Create a new factor from a vector of values
    pub fn from_vec(values: Vec<T>) -> Self {
        let mut levels = Vec::new();
        let mut indices = Vec::new();

        for value in values {
            if let Some(index) = levels.iter().position(|level| level == &value) {
                indices.push(index as u32);
            } else {
                levels.push(value);
                indices.push((levels.len() - 1) as u32);
            }
        }

        Self {
            indices,
            levels: Arc::new(levels),
        }
    }

    /// Get the number of levels
    pub fn n_levels(&self) -> usize {
        self.levels.len()
    }

    /// Get level labels
    pub fn levels(&self) -> &[T] {
        &self.levels
    }

    /// Get indices
    pub fn indices(&self) -> &[u32] {
        &self.indices
    }
}

